import machine
import umqtt.simple

# Define the client ID and broker IP address
client_id = "my-sensor"
broker_ip = "192.168.0.1"

# Create a new MQTTClient instance with the given client ID
mqttc = umqtt.simple.MQTTClient(client_id, broker_ip)

